var Json= getCordenadas();
var obj=JSON.parse(Json);
let latitude = obj[0].Latitude;
let longitude = obj[0].Longitude;

if (latitude !== undefined && longitude !== undefined && latitude !== null && longitude !== null) {
    form.getComponent("longitud").setValue(longitude);
    form.getComponent("latitud").setValue(latitude);
    var img = document.createElement("IMG");
    img.setAttribute("src", `https://maps.googleapis.com/maps/api/staticmap?size=400x400&zoom=16&maptype=roadmap&markers=size:xl%7Ccolor:red%7C${latitude},${longitude}&key=AIzaSyDTPEMAihgxEtqf4bGz_omi1BaayOpOJto`);
    img.setAttribute("width", "100%");
    img.setAttribute("height", "400");
    img.onload = function() {
        if ('naturalHeight' in this) {
            if (this.naturalHeight + this.naturalWidth === 0) {
                this.onerror();
                return;
            }
        } else if (this.width + this.height === 0) {
            this.onerror();
            return;
        }
        var node = document.getElementById("map-container");
        node.innerHTML = "";
        document.getElementById("map-container").appendChild(img);
    };
    img.onerror = function() {
      var node = document.getElementById("map-container");
      node.innerHTML = "";
    };
} else {
  Swal.fire({
      title: 'Geolocalización Incorrecta',
      text: "Intenta obtener las coordenadas nuevamente.",
      type: 'error',
      showCancelButton: false,
      confirmButtonColor: '#3085d6',
      confirmButtonText: 'Ok',
    }); 
}

