               // $("#everything-wrapper").fadeOut(600);

                if (entry.valor === "RECHAZADO") {
                    Swal.fire({
                        type: 'error',
                        title: 'Oops',
                        text: 'Cliente rechazado!',
                        footer: '<a href></a>'
                    })
                }

                if (entry.valor === "APROBADO") {
                    Swal.fire({
                        type: 'success',
                        title: 'Felicidades',
                        text: 'Cliente aprobado!',
                        footer: ''
                    })
                }

                if (entry.valor === "NO EXISTEN REGISTROS") {
                    Swal.fire({
                        type: 'warning',
                        title: 'Oops...',
                        text: 'Sin Registro en el buró!',
                        footer: '<a href></a>'
                    })
                }

                if (entry.valor === "") {
                    Swal.fire({
                        type: 'info',
                        title: 'Oops...',
                        text: 'Algo salio mal!',
                        footer: '<a href></a>'
                    })
